mapper.update:
UPDATE thesis_application
SET application_status = #{applicationStatus},
    review_time = NOW(),
    reviewer_id = #{reviewerId},
    remark = #{remark}
WHERE application_id = #{applicationId}

UPDATE thesis_application
SET application_status = 0, remark = #{remark}
WHERE topic_id = #{topicId} AND application_status = 1

UPDATE thesis_application
SET application_status = 0, remark = #{remark}
WHERE team_id = #{teamId} 
AND topic_id = #{topicId} 
AND application_status = 1
AND application_id NOT IN (
    SELECT application_id FROM (
        SELECT application_id 
        FROM thesis_application 
        WHERE team_id = #{teamId} 
        AND topic_id = #{topicId} 
        AND application_status = 1
        ORDER BY application_id ASC
        LIMIT 1
    ) AS temp
)

UPDATE thesis_application
SET application_status = 0, remark = #{remark}
WHERE student_id = #{studentId} AND application_status = 1

UPDATE thesis_application ta
JOIN team_member tm ON ta.student_id = tm.student_id
SET ta.application_status = 0, ta.remark = #{remark}
WHERE tm.team_id = #{teamId} AND ta.application_status = 1 AND ta.team_id = #{teamId}

UPDATE thesis_application
SET reserve_until = #{reserveUntil}
WHERE team_id = #{teamId} AND application_status = 1

